import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as s,f as n}from"./app-74137bf2.js";const a="/my-docs/assets/dev-d9d8774e.jpg",l="/my-docs/assets/dist-27bca942.jpg",c={},i=n('<h3 id="package-json的script中dev运行流程" tabindex="-1"><a class="header-anchor" href="#package-json的script中dev运行流程" aria-hidden="true">#</a> package.json的script中dev运行流程</h3><ol><li><code>npm run bootstrap</code>：<code>&quot;bootstrap&quot;: &quot;yarn || npm i&quot;</code>, 下载相关的依赖</li><li><code>npm run build:file</code>： <ul><li><code>&quot;build:file&quot;: &quot;node build/bin/iconInit.js &amp; node build/bin/build-entry.js &amp; node build/bin/i18n.js &amp; node build/bin/version.js&quot;,</code></li><li>生成一些文件：入口文件 图标 多语言 版本记录等</li></ul></li><li><code>cross-env NODE_ENV=development</code>： <ul><li><code>cross-env</code>传递环境变量的库，设置当前环境变量为开发模式</li></ul></li><li><code>webpack-dev-server --config build/webpack.demo.js</code>： <ul><li>指定webpack的配置文件为<code>build/webpack.demo.js</code>，并启动</li><li>找到入口文件为<code>./examples/entry.js</code>，目的是启动一个集成Element的系统</li></ul></li><li><code>node build/bin/template.js</code>：执行模版文件<br><img src="'+a+'" alt="image.png" loading="lazy"></li></ol><h3 id="package-json的script中dist运行流程-组件库的自动化打包流程" tabindex="-1"><a class="header-anchor" href="#package-json的script中dist运行流程-组件库的自动化打包流程" aria-hidden="true">#</a> package.json的script中dist运行流程？组件库的自动化打包流程？</h3><ol><li><code>npm run clean &amp;&amp; npm run build:file &amp;&amp; npm run lint</code>： <ul><li>&quot;clean&quot;: <code>&quot;rimraf lib &amp;&amp; rimraf packages/*/lib &amp;&amp; rimraf test/**/coverage&quot;,</code></li><li>查找<code>rimraf</code>，先去<code>node_module</code>的bin文件下查找有没有它，有的话则执行脚本，删除<code>packages/*/lib</code>文件夹下的内容</li><li>生成图标；生成入口文件；生成多语言文件；生成记录版本文件</li></ul></li><li><code>webpack --config build/webpack.conf.js</code><ul><li>在生成环境下以<code>src/index.js</code>为入口文件，将整体项目打包到<code>/lib</code>下面，输出文件为<code>index.js</code>，并且是<code>umd</code>规范，能够支持浏览器加载也能支持npm引入</li></ul></li><li><code>webpack --config build/webpack.common.js</code><ul><li>在生成环境下以<code>src/index.js</code>为入口文件，将整体项目打包到<code>/lib</code>下面，输出文件为<code>element-ui.common.js</code>，并且是<code>commonjs2</code>规范，支持require方式引入</li></ul></li><li><code>webpack --config build/webpack.component.js</code><ul><li>多入口打包，出口文件也有多个。输出文件为组件名.js 并且是commonjs2规范，支持require方式引入</li><li>这个是按需加载的前提，我们按需引入组件时候，需要写上<code>Vue.component(Button.name, Button);</code>或写为<code>Vue.use(Button)</code></li><li>Vue.use(Button)原理是<code>if(componnent.install){ 执行install函数 }</code>install其实就是<code>Vue.component(Button.name, Button)</code>;</li></ul></li><li><code>npm run build:utils &amp;&amp; npm run build:umd &amp;&amp; npm run build:theme</code><ul><li><code>&quot;build:utils&quot;</code>: <code>&quot;cross-env BABEL_ENV=utils babel src --out-dir lib --ignore src/index.js&quot;</code></li><li><code>&quot;build:umd&quot;</code>: <code>&quot;node build/bin/build-locale.js&quot;</code>, 多语言支持</li><li><code>&quot;build:theme&quot;</code>: <code>&quot;node build/bin/gen-cssfile &amp;&amp; gulp build --gulpfile packages/theme-chalk/gulpfile.js &amp;&amp; cp-cli packages/theme-chalk/lib lib/theme-chalk&quot;</code><ul><li><code>node build/bin/gen-cssfile</code>：根据packages下的theme-chalk文件的各个组件的scss文件相对路径自动化生成一个index.scss，是一个css入口文件</li><li><code>gulp build --gulpfile packages/theme-chalk/gulpfile.js</code> 1 将scss转成css 2 autoprefixer补上兼容的前缀 3 压缩 4 打包到/lib目录下</li><li>gulp 是一个前端构建工具，是进行压缩 转码 加工的功能单一、小巧易用的建构工具；</li><li>为什么混用gulp，为了按需引入，css与js做分离，gulp目的单纯小巧易用并且单类型转换，没必要用webpack<br><img src="'+l+`" alt="image.png" loading="lazy"></li></ul></li></ul></li></ol><h3 id="组件库按需加载的原理是什么" tabindex="-1"><a class="header-anchor" href="#组件库按需加载的原理是什么" aria-hidden="true">#</a> 组件库按需加载的原理是什么？</h3><ol><li>使用<code>webpack --config build/webpack.component.js</code>实现多入口打包，使每个组件有自己的输出文件</li><li>使用gulp工具转换scss文件，将css文件打包到lib目录下</li><li>用户引入需要插件：<code>babel-plugin-component</code>，它将用户输入的<code>import { Button, Select } from &#39;element-ui&#39;</code>;转为具体的被打包的js、css 路径文件，这样css和js就能被用户使用了。 <ul><li><code>babel-plugin-component</code>做了什么事情：将上面引入转为具体地址，<code>import Button from &#39;element-ui/lib/Button.js&#39;</code>;<code>import &#39;element-ui/lib/theme-chalk/Button.css&#39;; </code></li><li>原理是根据组件名曲lib目录下找同名的js组件、同名的css文件。</li></ul></li></ol><h3 id="webpack-demo-js文件详解" tabindex="-1"><a class="header-anchor" href="#webpack-demo-js文件详解" aria-hidden="true">#</a> webpack.demo.js文件详解</h3><ol><li><code>entry：&#39;./examples/entry.js&#39;</code> 入口文件</li><li><code>output：path.resolve(process.cwd(), &#39;./examples/element-ui/&#39;)</code>, 输出到examples的文件夹下</li><li><code>resolve：extensions: [&#39;.js&#39;, &#39;.vue&#39;, &#39;.json&#39;]</code>, 说明import引入文件时候，这些后缀可以自动补全；alias是路径别称</li><li><code>devServer</code>: 开启本地端口服务</li><li><code>module</code>:</li></ol><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code>  <span class="token punctuation">{</span>test<span class="token operator">:</span> /\\.(vue|jsx?)$/<span class="token punctuation">,</span>loader<span class="token operator">:</span> &#39;eslint-loader&#39;<span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span>test<span class="token operator">:</span> /\\.(jsx?|babel|es6)$/<span class="token punctuation">,</span>include<span class="token operator">:</span> process.cwd()<span class="token punctuation">,</span>loader<span class="token operator">:</span> &#39;babel-loader&#39;<span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token comment">// 把 ES6 转换成 ES5 </span>
  <span class="token punctuation">{</span>test<span class="token operator">:</span> /\\.vue$/<span class="token punctuation">,</span>.loader<span class="token operator">:</span>&#39;vue-loader&#39;<span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span>test<span class="token operator">:</span> /\\.(scss|css)$/<span class="token punctuation">,</span> use<span class="token operator">:</span> <span class="token punctuation">[</span>&#39;style-loader&#39;<span class="token punctuation">,</span>&#39;css-loader&#39;<span class="token punctuation">,</span>&#39;sass-loader&#39;<span class="token punctuation">]</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token comment">//从右往左解析:sass-loader：sass转css；css-loader：加载 CSS，⽀持模块化、压缩、⽂件导⼊；style-loader：把 CSS 代码注⼊到 JavaScript 中，通过 DOM 操作去加载 CSS</span>
  <span class="token punctuation">{</span>test<span class="token operator">:</span> /\\.md$/<span class="token punctuation">,</span>use<span class="token operator">:</span> <span class="token punctuation">[</span> loader<span class="token operator">:</span> &#39;vue-loader&#39;<span class="token punctuation">,</span> loader<span class="token operator">:</span> path.resolve(__dirname<span class="token punctuation">,</span> &#39;./md-loader/index.js&#39;)<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="md-loader文件详解-与组件的文档实例有关。" tabindex="-1"><a class="header-anchor" href="#md-loader文件详解-与组件的文档实例有关。" aria-hidden="true">#</a> md-loader文件详解？与组件的文档实例有关。</h3><ol><li><code>markdown-it</code>解析<code>markdown</code>的库，将<code>markdown</code>代码编译我们可以使用的抽象语法树。</li><li><code>containers.js</code>：作用是将<code>:::demo</code>转为注释节点，将里面内容放在<code>&lt;demo-block&gt;&lt;!--element-demo&gt;</code>标签里面</li><li><code>index.js</code>：拿到经过初步处理后的文件后，匹配拿出<code>&lt;!--element-demo&gt;</code>里面的内容，包裹在<code>&lt;template slot=&quot;source&quot;&gt;&lt;/template&gt;</code>里面，并经过加工，最终变成一个vue文件，</li><li>再有<code>vue-loader</code>处理。</li><li><code>&lt;demo-block&gt;</code>包裹了内容，所以实例界面可以并交互并折叠组件</li></ol><h3 id="如何自动化创建组件" tabindex="-1"><a class="header-anchor" href="#如何自动化创建组件" aria-hidden="true">#</a> 如何自动化创建组件？</h3><ol><li><code>Makefile</code>：管理命令，命令的集合入口，如<code>dev:npm run dev</code>: <code>new:node build/bin/new.js $(filter-out $@,$(MAKECMDGOALS))</code></li><li>用户输入<code>new select</code>,那么就会自动去创建新的组件的相关文件，比如select组件的<code>index文件，vue文件，css文件</code>等等会自动创建出来，这样子就不用一个一个去创建相关文件，节省重复事情，避免出问题。</li><li>在终端输入<code>new</code>，系统就 <ul><li>①执行了<code>build/bin/new.js</code>文件，然后根据传入的项目名字参数，生成<code>packages</code>下面的组件文件，</li><li>②并且把组件名、相对路径添加到添加到<code>components.json</code>，</li><li>③sass模板内容添加到<code>index.scss</code>添加ts文件；</li><li>④添加组件名到<code>nav.config.json</code>导航文件等。</li></ul></li><li>很多脚手架的新建组件、新建文件、自动生成配置文件，都有这种自动化流程。目的是减少手动添加文件、引入文件，做到减少重复无聊的步骤。</li></ol><h3 id="多语言支持原理" tabindex="-1"><a class="header-anchor" href="#多语言支持原理" aria-hidden="true">#</a> 多语言支持原理</h3><ol><li>把<code>src/locale/lang</code>下的多语言文件进行打包，用户可以通过<code>import lang from &#39;element-ui/lib/locale/lang/en&#39;;locale.use(lang)</code>来引入</li><li>其中原理是利用占位符，不同语言占位符可以替换为不同内容</li></ol>`,15),d=[i];function t(p,u){return o(),s("div",null,d)}const b=e(c,[["render",t],["__file","组件库之构建.html.vue"]]);export{b as default};
